class Solution:
    def canSplitArray(self, nums, m):
        n = len(nums)
        prefix = [0] * (n + 1)
        for i, v in enumerate(nums):
            prefix[i + 1] = prefix[i] + v
        def is_good(l, r):
            return (r - l + 1) == 1 or (prefix[r + 1] - prefix[l]) >= m
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def can_split(l, r):
            if l == r:
                return True
            for i in range(l, r):
                if is_good(l, i) and is_good(i + 1, r) and can_split(l, i) and can_split(i + 1, r):
                    return True
            return False
        result = can_split(0, n - 1)
        can_split.cache_clear()
        return result

